#!/usr/bin/env python3
"""gguf-to-knot.py

Re-pack a GGUF file's tensor payload into the KNOT file format that
fat-station's `KnotWeights::load_mmap` already loads.

Why: fat-station consumes KNOT (magic "KNOT" + JSON metadata + concatenated
quantized tensor bytes) with the same per-quant dequantizers llama.cpp uses
internally (Q4_K, Q5_0, Q5_K, Q6_K, Q8_0). GGUF stores those same bytes in
the same on-disk format — we just need to re-emit them under the KNOT header
and translate tensor names from GGUF's dotted convention
(`blk.0.attn_q.weight`) to KNOT's underscore convention
(`blk_0_attn_q_weight.bin`).

We DO NOT re-quantize. Each tensor's bytes are copied verbatim from the
GGUF blob. Block alignment is preserved (Q4_K = 144 B / 256-element
super-block, Q5_0 = 22 B / 32-element block, etc.).

KNOT header (per src/loader.rs):
    bytes 0..4   : "KNOT" magic
    bytes 4..6   : version u16 LE (= 1)
    bytes 6..10  : meta_len u32 LE
    bytes 10..10+meta_len : metadata JSON, UTF-8
    pad to 4-byte alignment
    1 byte codec marker (0x20 for fp32-default — fat-station's codec byte is
                         only consulted for the top-level OwnedBytes interp;
                         per-tensor types come from `tensors[name].type`)
    tensor payload

Tensor-name translation: every `.` in the GGUF tensor name becomes `_`, then
we append `.bin`. fat-station's `parse_tensors` strips the `.bin` suffix
before storing, so the in-memory key matches `blk_<L>_attn_q_weight`, which
is what `model.rs::resolve_all` looks up.

Usage:
    python3 gguf-to-knot.py INPUT.gguf OUTPUT.knot [--name MODEL_NAME]

Tested against:
    bartowski/Qwen2.5-0.5B-Instruct-GGUF Q4_K_M (24 layers, 290 tensors).
"""
from __future__ import annotations

import argparse
import json
import os
import struct
import sys
import time
from typing import Any

import numpy as np
from gguf import GGUFReader, GGUFValueType

# ─────────────────────────────────────────────────────────────────────────
# Type-code → KNOT type-string table
# ─────────────────────────────────────────────────────────────────────────
# Values from llama.cpp ggml.h GGML_TYPE_* enum; mapped to the strings that
# fat-station's model.rs::resolve_type matches (Q4_K/Q5_0/Q5_K/Q6_K/Q8_0/F32).
# F16 has no direct QType variant — we dequantize to F32 to avoid silent
# misinterpretation.
GGML_TYPE_TO_KNOT = {
    0: "F32",  # GGML_TYPE_F32
    1: "F16->F32",  # GGML_TYPE_F16 — needs dequant
    6: "Q5_0",  # GGML_TYPE_Q5_0
    8: "Q8_0",  # GGML_TYPE_Q8_0
    12: "Q4_K",  # GGML_TYPE_Q4_K
    13: "Q5_K",  # GGML_TYPE_Q5_K
    14: "Q6_K",  # GGML_TYPE_Q6_K
    # IQ codebook types (E8-grid family), byte-verbatim like the K-quants.
    # Real ggml block sizes: IQ2_S = 82 B / 256 elems, IQ3_S = 110 B / 256.
    # Serving kernels: distributed-inference/src/iq_dequant.rs (2026-07-08).
    21: "IQ3_S",  # GGML_TYPE_IQ3_S
    22: "IQ2_S",  # GGML_TYPE_IQ2_S
}


def gguf_name_to_knot(name: str) -> str:
    """`blk.0.attn_q.weight` → `blk_0_attn_q_weight.bin`."""
    return name.replace(".", "_") + ".bin"


def scalar(field) -> Any:
    """Best-effort scalar extraction from a GGUF metadata field.

    GGUF fields are laid out as a sequence of byte blobs in `field.parts`,
    with `field.data` giving the indices of the actual VALUE blobs (header
    blobs hold type tag + length). For STRING values, `parts[data[0]]` is
    the raw utf-8 bytes; for numeric scalars it's the numpy array of length
    1; for arrays it's a longer numpy array.
    """
    if not field.parts or not field.data:
        return None
    value_idx = field.data[0]
    part = field.parts[value_idx]
    # String fields: take all parts referenced by `data` and concat as bytes.
    if field.types and field.types[-1] == GGUFValueType.STRING:
        return bytes(part).decode("utf-8", errors="replace")
    # Numeric scalar/array: numpy array.
    if hasattr(part, "tolist"):
        v = part.tolist()
        if isinstance(v, list) and len(v) == 1:
            return v[0]
        return v
    if isinstance(part, (bytes, bytearray)):
        try:
            return bytes(part).decode("utf-8")
        except Exception:
            return None
    return part


def build_config(r: GGUFReader, arch: str) -> dict:
    """Build the KNOT `config` block from GGUF metadata.

    Architecture-aware: emits the standard dense-transformer fields for every
    arch, then augments with arch-specific fields the fat-station pipeline
    consumes. For gemma3/gemma4 this is the softcap / sliding-window / dual-RoPE
    block (see loader.rs::KnotConfig and model_gemma4.rs); without these the
    Gemma4Pipeline runs with the wrong attention scale, no logit softcap, and
    all-global attention — i.e. silently wrong logits. The values are read
    straight from the GGUF KV metadata, which is what llama.cpp itself uses to
    run the model correctly (the HF config.json nulls several of them out for
    gemma4, so the GGUF header is the authoritative source here).
    """
    # Architecture prefixes vary: qwen2.embedding_length, llama.embedding_length, etc.
    g = lambda k, default=None: (
        scalar(r.fields[k]) if k in r.fields else default
    )

    hidden_dim = g(f"{arch}.embedding_length")
    num_heads = g(f"{arch}.attention.head_count")
    num_kv_heads = g(f"{arch}.attention.head_count_kv", num_heads)
    head_dim = g(f"{arch}.attention.key_length")
    if head_dim is None and hidden_dim is not None and num_heads:
        head_dim = hidden_dim // num_heads

    # Vocab: the token-embedding matrix is authoritative for the model's vocab
    # DIMENSION (it may be padded above the tokenizer's token count — e.g.
    # qwen35moe token_embd is 248320 while the BPE has ~151936). Prefer the
    # embedding/output tensor shape; fall back to tokenizer count / vocab_size key.
    vocab_size = None
    for t in r.tensors:
        if t.name in ("token_embd.weight", "output.weight"):
            try:
                vocab_size = int(max(int(d) for d in t.shape))
            except Exception:
                vocab_size = None
            if vocab_size:
                break
    if not vocab_size and "tokenizer.ggml.tokens" in r.fields:
        try:
            vocab_size = len(r.fields["tokenizer.ggml.tokens"].data)
        except Exception:
            vocab_size = None
    if not vocab_size:
        vocab_size = g(f"{arch}.vocab_size")

    # MoE archs (qwen35moe, qwen3moe) have no dense feed_forward_length; fall back
    # to the per-expert FFN length so intermediate_size is always populated.
    ffn_len = g(f"{arch}.feed_forward_length")
    if ffn_len is None:
        ffn_len = g(f"{arch}.expert_feed_forward_length", 0)

    # gemma stores per-layer head_count_kv / sliding pattern as ARRAYS. The
    # sliding (local) layers carry the larger KV-head count; global layers the
    # smaller one. fat-station's Config wants the sliding value as the default
    # `num_kv_heads` and the global value as `global_num_kv_heads`.
    def _as_list(v):
        return v if isinstance(v, list) else ([v] if v is not None else [])

    cfg = {
        "hidden_dim": int(hidden_dim),
        "num_layers": int(g(f"{arch}.block_count")),
        "num_heads": int(num_heads),
        "num_kv_heads": int(num_kv_heads if not isinstance(num_kv_heads, list)
                          else max(num_kv_heads)),
        "head_dim": int(head_dim),
        "intermediate_size": int(ffn_len),
        "vocab_size": int(vocab_size),
        "rms_norm_eps": float(g(f"{arch}.attention.layer_norm_rms_epsilon", 1e-5)),
        "rope_theta": float(g(f"{arch}.rope.freq_base", 10000.0)),
        "arch": arch,
    }

    if arch in ("gemma3", "gemma4"):
        # head_dim base = sliding/local head dim (key_length_swa); the larger
        # key_length is the GLOBAL-attention head dim.
        kl = g(f"{arch}.attention.key_length")
        kl_swa = g(f"{arch}.attention.key_length_swa", kl)

        # gemma stores head_count_kv and sliding_window_pattern as PER-LAYER
        # arrays (one entry per block), not scalars — scalar() only reads the
        # first element, which silently dropped global_num_kv_heads /
        # sliding_window_pattern and made the pipeline treat EVERY layer as
        # global (wrong q/k weight sizing -> mat_vec panic). Read all parts.
        def _full_array(key):
            if key not in r.fields:
                return []
            fld = r.fields[key]
            out = []
            for idx in fld.data:
                part = fld.parts[idx]
                v = part.tolist() if hasattr(part, "tolist") else part
                if isinstance(v, list):
                    v = v[0] if len(v) == 1 else v
                out.append(v)
            return out

        kv_arr = _full_array(f"{arch}.attention.head_count_kv")
        sw_pattern_arr = _full_array(f"{arch}.attention.sliding_window_pattern")

        if kl_swa is not None:
            cfg["head_dim"] = int(kl_swa)
        if kl is not None and kl != kl_swa:
            cfg["global_head_dim"] = int(kl)
        if kv_arr:
            cfg["num_kv_heads"] = int(max(kv_arr))          # sliding layers
            if min(kv_arr) != max(kv_arr):
                cfg["global_num_kv_heads"] = int(min(kv_arr))  # global layers

        # Final-logit tanh softcap (gemma: 30.0).
        softcap = g(f"{arch}.final_logit_softcapping")
        if softcap is not None:
            cfg["final_logit_softcap"] = float(softcap)

        # Q-side pre-attention scalar. gemma uses embedding_length / head_count
        # (Gemma4-31B = 5376/32 = 168.0; Gemma4-E4B = 2048/8 = 256.0), which is
        # NOT stored as a GGUF key — derive it.
        if hidden_dim and num_heads:
            cfg["query_pre_attn_scalar"] = float(int(hidden_dim) // int(num_heads))

        # Sliding-window attention: size + global-layer period. The pattern is a
        # per-layer bool array (True = sliding, False = global); the period is
        # the spacing between global layers.
        sw_size = g(f"{arch}.attention.sliding_window")
        if sw_size is not None:
            cfg["sliding_window"] = int(sw_size)
        if sw_pattern_arr:
            bools = [bool(x) for x in sw_pattern_arr]  # True=sliding, False=global
            # The pipeline treats layer L as global when (L+1) % pattern == 0,
            # so pattern = (index of the first global layer) + 1 (first global
            # at index 5 -> pattern 6).
            if False in bools:
                cfg["sliding_window_pattern"] = bools.index(False) + 1

        # Dual-base RoPE: global layers use freq_base, sliding layers freq_base_swa.
        local_theta = g(f"{arch}.rope.freq_base_swa")
        if local_theta is not None:
            cfg["rope_local_base_freq"] = float(local_theta)
        rope_scale = g(f"{arch}.rope.scaling.factor")
        if rope_scale is not None:
            cfg["rope_scaling_factor"] = float(rope_scale)
        # Partial RoPE: rotate rope.dimension_count of head_dim. Only emit when
        # it is actually partial (dim_count < head_dim); equal ⇒ full rotation.
        rope_dim = g(f"{arch}.rope.dimension_count")
        base_hd = cfg.get("global_head_dim", cfg["head_dim"])
        if rope_dim is not None and base_hd and int(rope_dim) < int(base_hd):
            cfg["rope_partial_factor"] = float(int(rope_dim) / int(base_hd))

    if arch in ("qwen35moe", "qwen3moe", "qwen3next"):
        # Qwen3-Next-class hybrid MoE. The expert/SSM/interval fields the
        # Qwen35MoePipeline consumes (or defaults for now); emitted so the knot
        # is self-describing. serde ignores keys KnotConfig doesn't read yet.
        ec = g(f"{arch}.expert_count")
        euc = g(f"{arch}.expert_used_count")
        if ec is not None:
            cfg["num_experts"] = int(ec)
        if euc is not None:
            cfg["num_experts_per_tok"] = int(euc)
        for key, fld in (
            ("expert_ff_len", "expert_feed_forward_length"),
            ("shared_expert_ff_len", "expert_shared_feed_forward_length"),
            ("full_attention_interval", "full_attention_interval"),
            ("ssm_state_size", "ssm.state_size"),
            ("ssm_conv_kernel", "ssm.conv_kernel"),
            ("ssm_group_count", "ssm.group_count"),
            ("ssm_inner_size", "ssm.inner_size"),
            ("ssm_time_step_rank", "ssm.time_step_rank"),
            ("rope_dim_count", "rope.dimension_count"),
        ):
            v = g(f"{arch}.{fld}")
            if v is not None:
                cfg[key] = int(v)
        sections = g(f"{arch}.rope.dimension_sections")
        if sections is not None:
            cfg["mrope_sections"] = [int(x) for x in _as_list(sections)]

    return cfg


def _materialize_tensor(t, is_f16: bool) -> bytes:
    """Raw KNOT payload bytes for one GGUF tensor, produced on demand so the
    writer never holds more than one tensor in RAM. Verbatim quantized bytes for
    every supported QType; F16 is dequantized to F32 (fat-station has no F16)."""
    if is_f16:
        return np.asarray(t.data, dtype=np.float16).astype(np.float32).tobytes()
    return bytes(t.data.tobytes())


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("input_gguf")
    ap.add_argument("output_knot")
    ap.add_argument("--name", default=None, help="model name in KNOT metadata")
    args = ap.parse_args()

    t0 = time.time()
    print(f"[gguf-to-knot] reading {args.input_gguf}", file=sys.stderr)
    r = GGUFReader(args.input_gguf)
    print(
        f"[gguf-to-knot] {len(r.tensors)} tensors, {len(r.fields)} metadata fields",
        file=sys.stderr,
    )

    arch_str = scalar(r.fields["general.architecture"])
    if isinstance(arch_str, (bytes, bytearray)):
        arch_str = bytes(arch_str).decode("utf-8")
    print(f"[gguf-to-knot] arch={arch_str}", file=sys.stderr)

    config = build_config(r, arch_str)
    print(f"[gguf-to-knot] config={config}", file=sys.stderr)

    # ── Walk tensors: build tensor-info metadata + a LIGHTWEIGHT write order ──
    # We assign payload offsets sequentially in GGUF order, recording translated
    # name + length + type-string. We do NOT materialize tensor bytes here: for a
    # multi-GB model that would hold the ENTIRE payload in RAM at once (e.g. an
    # 18 GB spike for a 31B Q4_K_M), which thrashes/OOMs and can get the process
    # killed mid-write. Instead we stream each tensor straight from the GGUF mmap
    # at write time (peak RAM ~ one tensor).
    tensors_meta: dict[str, dict] = {}
    write_order: list[tuple[str, Any, bool]] = []  # (knot_name, gguf_tensor, is_f16_dequant)

    cur_off = 0
    n_unknown = 0
    for t in r.tensors:
        knot_name = gguf_name_to_knot(t.name)
        gtype = int(t.tensor_type)
        ktype_str = GGML_TYPE_TO_KNOT.get(gtype)
        if ktype_str is None:
            print(
                f"[gguf-to-knot] WARNING: unknown ggml type {gtype} for {t.name}; "
                f"skipping",
                file=sys.stderr,
            )
            n_unknown += 1
            continue

        # F16 → F32 dequant doubles the byte length (2 → 4 bytes/elem); verbatim
        # quant tensors keep their on-disk length. fat-station's QType lacks F16,
        # so we dequant F16 to F32 to avoid a silent misread.
        is_f16 = ktype_str == "F16->F32"
        if is_f16:
            length = 2 * int(t.n_bytes)
            ktype_str = "F32"
        else:
            length = int(t.n_bytes)

        write_order.append((knot_name, t, is_f16))
        tensors_meta[knot_name] = {
            "offset": cur_off,
            "length": length,
            "type": ktype_str,
        }
        cur_off += length

    print(
        f"[gguf-to-knot] planned {len(write_order)} tensors, "
        f"{cur_off:,} payload bytes, skipped {n_unknown} unknown",
        file=sys.stderr,
    )

    # ── Build metadata JSON ─────────────────────────────────────────────────
    model_name = args.name or os.path.splitext(os.path.basename(args.output_knot))[0]
    metadata = {
        "name": model_name,
        "codec": "fp32",
        "topology": "transformer-decoder",
        "config": config,
        "tensors": tensors_meta,
    }
    meta_bytes = json.dumps(metadata, separators=(",", ":")).encode("utf-8")
    meta_len = len(meta_bytes)
    # Pad to 4-byte alignment AFTER the 10-byte fixed header + meta JSON.
    payload_offset_pre_marker = (10 + meta_len + 3) & ~3
    pad_len = payload_offset_pre_marker - (10 + meta_len)
    payload_offset = payload_offset_pre_marker + 1  # +1 for codec marker
    codec_marker = 0x20  # fp32 default

    print(
        f"[gguf-to-knot] meta_len={meta_len} pad={pad_len} payload_offset={payload_offset}",
        file=sys.stderr,
    )

    # ── Write the KNOT file ─────────────────────────────────────────────────
    with open(args.output_knot, "wb") as f:
        f.write(b"KNOT")
        f.write(struct.pack("<H", 1))  # version 1
        f.write(struct.pack("<I", meta_len))
        f.write(meta_bytes)
        if pad_len:
            f.write(b"\x00" * pad_len)
        f.write(bytes([codec_marker]))
        # Tensor payload — STREAM one tensor at a time straight from the GGUF
        # mmap (peak RAM ~ one tensor, not the whole model).
        for knot_name, t, is_f16 in write_order:
            raw = _materialize_tensor(t, is_f16)
            if not is_f16 and len(raw) != int(t.n_bytes):
                print(
                    f"[gguf-to-knot] WARN: length mismatch on {knot_name}: "
                    f"got {len(raw)}, expected {t.n_bytes}",
                    file=sys.stderr,
                )
            f.write(raw)
            del raw

    out_size = os.path.getsize(args.output_knot)
    elapsed = time.time() - t0
    print(
        f"[gguf-to-knot] wrote {args.output_knot} ({out_size:,} bytes) in {elapsed:.2f}s",
        file=sys.stderr,
    )

    # ── Quick reverse round-trip sanity check ───────────────────────────────
    # Re-read the file's header, confirm magic / meta JSON parses / a sampled
    # tensor's bytes equal the GGUF source bytes.
    with open(args.output_knot, "rb") as f:
        magic = f.read(4)
        assert magic == b"KNOT", f"bad magic: {magic!r}"
        ver = struct.unpack("<H", f.read(2))[0]
        ml = struct.unpack("<I", f.read(4))[0]
        meta_back = json.loads(f.read(ml).decode("utf-8"))
        # padded read up to codec marker
        cur = 10 + ml
        pad2 = ((cur + 3) & ~3) - cur
        f.read(pad2)
        cm = f.read(1)[0]
        assert cm == codec_marker, f"codec marker mismatch: {cm:#x}"
        # Sample 3 tensors (first, middle, last) and verify
        sample_names = (
            list(tensors_meta.keys())[0],
            list(tensors_meta.keys())[len(tensors_meta) // 2],
            list(tensors_meta.keys())[-1],
        )
        payload_start = f.tell()
        plan_by_name = {kn: (t, is_f16) for kn, t, is_f16 in write_order}
        for kname in sample_names:
            info = meta_back["tensors"][kname]
            f.seek(payload_start + info["offset"])
            got = f.read(info["length"])
            # Re-materialize the source tensor's bytes on demand (write_order
            # holds the GGUF tensor ref, not the bytes) and compare.
            t_src, is_f16_src = plan_by_name[kname]
            expected = _materialize_tensor(t_src, is_f16_src)
            ok = got == expected
            print(
                f"[gguf-to-knot] round-trip {kname}: "
                f"len={len(got):,} match={ok}",
                file=sys.stderr,
            )
            if not ok:
                print(
                    "[gguf-to-knot] ROUND-TRIP MISMATCH — refusing",
                    file=sys.stderr,
                )
                sys.exit(2)

    print("[gguf-to-knot] OK", file=sys.stderr)


if __name__ == "__main__":
    main()
